class WebViewPage extends StatefulWidget {
  @override
  _WebViewPageState createState() => _WebViewPageState();
}

class _WebViewPageState extends State<WebViewPage> {
  late WebViewController _controller;
  final ImagePicker _imagePicker = ImagePicker();
  final FirebaseMessaging _firebaseMessaging = FirebaseMessaging.instance;
  String? _fcmToken;

  @override
  void initState() {
    super.initState();
    _initializePushNotifications();
  }

  Future<void> _initializePushNotifications() async {
    NotificationSettings settings = await _firebaseMessaging.requestPermission(
      alert: true,
      badge: true,
      sound: true,
    );

    if (settings.authorizationStatus == AuthorizationStatus.authorized) {
      _fcmToken = await _firebaseMessaging.getToken();
      print('FCM Token: $_fcmToken');

      FirebaseMessaging.onMessage.listen((RemoteMessage message) {
        _handlePushNotification(message);
      });

      FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {
        _handlePushNotification(message);
      });
    }
  }

  void _handlePushNotification(RemoteMessage message) {
    final data = {
      'title': message.notification?.title ?? '',
      'body': message.notification?.body ?? '',
      'data': message.data,
    };
    _sendMessageToWeb('onPushNotification', data);
  }

  void _sendMessageToWeb(String event, dynamic data) {
    final message = jsonEncode({'event': event, 'data': data});
    _controller.runJavaScript(
      "if (window.flutterMessageHandler) { window.flutterMessageHandler($message); }",
    );
  }

  Future<void> _openCamera() async {
    try {
      final XFile? photo = await _imagePicker.pickImage(
        source: ImageSource.camera,
        imageQuality: 85,
      );
      if (photo != null) {
        final bytes = await photo.readAsBytes();
        final base64Image = base64Encode(bytes);
        _sendMessageToWeb('onCameraResult', {
          'success': true,
          'path': photo.path,
          'base64': base64Image,
        });
      } else {
        _sendMessageToWeb('onCameraResult', {'success': false});
      }
    } catch (e) {
      _sendMessageToWeb('onCameraResult', {
        'success': false,
        'error': e.toString(),
      });
    }
  }

  Future<void> _openGallery() async {
    try {
      final XFile? image = await _imagePicker.pickImage(
        source: ImageSource.gallery,
        imageQuality: 85,
      );
      if (image != null) {
        final bytes = await image.readAsBytes();
        final base64Image = base64Encode(bytes);
        _sendMessageToWeb('onGalleryResult', {
          'success': true,
          'path': image.path,
          'base64': base64Image,
        });
      } else {
        _sendMessageToWeb('onGalleryResult', {'success': false});
      }
    } catch (e) {
      _sendMessageToWeb('onGalleryResult', {
        'success': false,
        'error': e.toString(),
      });
    }
  }

  Future<void> _getFCMToken() async {
    _sendMessageToWeb('onFCMToken', {
      'token': _fcmToken ?? '',
    });
  }

  void _handleJavaScriptMessage(JavaScriptMessage message) {
    try {
      final data = jsonDecode(message.message);
      final action = data['action'] as String?;

      switch (action) {
        case 'openCamera':
          _openCamera();
          break;
        case 'openGallery':
          _openGallery();
          break;
        case 'getFCMToken':
          _getFCMToken();
          break;
        case 'showToast':
          _showToast(data['message'] ?? 'No message');
          break;
        case 'vibrate':
          _vibrate();
          break;
        default:
          print('Unknown action: $action');
      }
    } catch (e) {
      print('Error handling JavaScript message: $e');
    }
  }

  void _showToast(String message) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        duration: Duration(seconds: 2),
      ),
    );
  }

  void _vibrate() {
    print('Vibrate requested');
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Hybrid WebView'),
        actions: [
          IconButton(
            icon: Icon(Icons.refresh),
            onPressed: () {
              _controller.reload();
            },
          ),
        ],
      ),
      body: SafeArea(
        child: WebView(
          initialUrl: 'https://your-mobile-website.com',
          javascriptMode: JavascriptMode.unrestricted,
          onWebViewCreated: (WebViewController controller) {
            _controller = controller;
          },
          javascriptChannels: {
            JavascriptChannel(
              name: 'FlutterChannel',
              onMessageReceived: _handleJavaScriptMessage,
            ),
          },
          onPageStarted: (String url) {
            print('Page started loading: $url');
          },
          onPageFinished: (String url) {
            print('Page finished loading: $url');
            _injectJavaScript();
          },
          onWebResourceError: (WebResourceError error) {
            print('Web resource error: ${error.description}');
          },
          gestureNavigationEnabled: true,
          allowsInlineMediaPlayback: true,
        ),
      ),
    );
  }

  void _injectJavaScript() {
    _controller.runJavaScript('''
      window.FlutterBridge = {
        openCamera: function() {
          FlutterChannel.postMessage(JSON.stringify({action: 'openCamera'}));
        },
        openGallery: function() {
          FlutterChannel.postMessage(JSON.stringify({action: 'openGallery'}));
        },
        getFCMToken: function() {
          FlutterChannel.postMessage(JSON.stringify({action: 'getFCMToken'}));
        },
        showToast: function(message) {
          FlutterChannel.postMessage(JSON.stringify({action: 'showToast', message: message}));
        },
        vibrate: function() {
          FlutterChannel.postMessage(JSON.stringify({action: 'vibrate'}));
        }
      };
      
      window.flutterMessageHandler = function(message) {
        const event = new CustomEvent('flutterMessage', { detail: message });
        window.dispatchEvent(event);
      };
      
      console.log('Flutter Bridge initialized');
    ''');
  }
}